#!/usr/bin/env node
// Gigzito — Single-file deploy: index.css
// Generated: 2026-03-10T01:04:11.801Z
// Fix: @import must be line 1 (PostCSS rejects it elsewhere — breaks ALL CSS compilation)
//      Unlayered override block at bottom (feed height fix)
//
// Usage on VPS:  node /tmp/deploy_css.js
// Then restart:  pm2 delete gigzito && pm2 start npm --name gigzito -- run dev
//
const fs = require('fs');
const path = require('path');
const TARGET = '/opt/gigzito/client/src/index.css';
const B64 = '';
fs.mkdirSync(path.dirname(TARGET), { recursive: true });
const buf = Buffer.from(B64, 'base64');
fs.writeFileSync(TARGET, buf);
console.log('OK ' + buf.length + ' bytes written to ' + TARGET);
console.log('Line 1 should be: @import url(https://fonts.googleapis.com...)');
console.log('\nRestart server:');
console.log('  pm2 delete gigzito && pm2 start npm --name gigzito -- run dev');
